const body = $json.body ?? $json;

// Bot message guard - discard if message is from a bot
if (body.authorIsBot === true) {
  return [];
}

const requiredInput = ['discordUser', 'discordUserId', 'messageTimestamp', 'submittedDate', 'imageBase64'];
const missingInput = requiredInput.filter((key) => !body[key]);

return [{
  json: {
    discordUser: body.discordUser || 'Unknown user',
    discordUserId: body.discordUserId || '',
    messageTimestamp: body.messageTimestamp || new Date().toISOString(),
    submittedDate: body.submittedDate || new Date().toISOString().slice(0, 10),
    messageId: body.messageId || '',
    channelId: body.channelId || '',
    imageBase64: body.imageBase64 || '',
    mimeType: body.mimeType || 'image/jpeg',
    inputMissingFields: missingInput
  }
}];

const original = $('Normalize Discord Input').first().json;
const response = $json;

function safeString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function parseLlmJson(resp) {
  if (resp.error || resp.message?.includes?.('Error')) {
    return { apiUnavailable: true, invalidJson: false, parseError: null, aiRawText: '', extracted: null };
  }
  const text =
    resp.choices?.[0]?.message?.content ??
    resp.body?.choices?.[0]?.message?.content ??
    resp.data?.choices?.[0]?.message?.content ??
    '';
  if (!text) {
    return { apiUnavailable: true, invalidJson: false, parseError: null, aiRawText: '', extracted: null };
  }
  try {
    const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
    return { apiUnavailable: false, invalidJson: false, parseError: null, aiRawText: text, extracted: JSON.parse(cleaned) };
  } catch (error) {
    return { apiUnavailable: false, invalidJson: true, parseError: error.message, aiRawText: text, extracted: { ReceiptDetected: false } };
  }
}

const parsed = parseLlmJson(response);

if (parsed.apiUnavailable) {
  return [{
    json: {
      ...original,
      apiUnavailable: true,
      receiptDetected: false,
      logEvent: 'AIUnavailable',
      logLabel: 'error',
      status: 'Rejected',
      details: 'LLM endpoint unreachable or returned no usable response.',
      discordMessage: `⚠️ <@${original.discordUserId}> your receipt could not be processed because the AI service is unavailable. Please try again later.`
    }
  }];
}

if (parsed.invalidJson) {
  const rawHead = (parsed.aiRawText || '').slice(0, 200).replace(/\s+/g, ' ');
  return [{
    json: {
      ...original,
      apiUnavailable: false,
      receiptDetected: false,
      logEvent: 'AIResponseInvalid',
      logLabel: 'error',
      status: 'Rejected',
      details: `AI returned non-JSON output: ${parsed.parseError}. Raw head: ${rawHead}`,
      aiRawText: parsed.aiRawText,
      discordMessage: `❌ <@${original.discordUserId}> the AI response was unreadable. Please re-upload the receipt.`
    }
  }];
}

const ai = parsed.extracted || {};
const receiptDetected = ai.ReceiptDetected === true;

if (!receiptDetected) {
  return [{
    json: {
      ...original,
      apiUnavailable: false,
      receiptDetected: false,
      logEvent: 'NoReceiptDetected',
      logLabel: 'warning',
      status: 'Rejected',
      details: `Image classified as non-receipt. AI notes: ${safeString(ai.Notes) || 'no notes provided'}`,
      aiRawText: parsed.aiRawText,
      discordMessage: `❌ <@${original.discordUserId}> no valid receipt was detected. Please send a new image of the receipt.`
    }
  }];
}

const merged = {
  discordUser: original.discordUser,
  discordUserId: original.discordUserId,
  messageTimestamp: original.messageTimestamp,
  submittedDate: original.submittedDate,
  messageId: original.messageId,
  channelId: original.channelId,
  merchant: safeString(ai.Merchant),
  receiptDate: safeString(ai.ReceiptDate),
  currency: safeString(ai.Currency),
  totalAmount: ai.TotalAmount ?? '',
  vatAmount: ai.VATAmount ?? '',
  vatIncluded: safeString(ai.VATIncluded),
  category: safeString(ai.Category),
  paymentMethod: safeString(ai.PaymentMethod),
  receiptId: safeString(ai.ReceiptId),
  businessPurpose: safeString(ai.BusinessPurpose),
  confidence: ai.Confidence ?? '',
  notes: safeString(ai.Notes)
};

const requiredFields = [
  ['Merchant', merged.merchant],
  ['Receipt Date', merged.receiptDate],
  ['Currency', merged.currency],
  ['Total Amount', merged.totalAmount],
  ['VAT Amount', merged.vatAmount],
  ['Category', merged.category],
  ['Payment Method', merged.paymentMethod]
];

const missingFields = requiredFields
  .filter(([_, value]) => value === '' || value === null || value === undefined)
  .map(([field]) => field);

const hasMissingFields = missingFields.length > 0;
const status = hasMissingFields ? 'Pending Review' : 'Approved by Bot';

const aiSummary = `Merchant: ${merged.merchant || '(blank)'}, Total: ${merged.totalAmount === '' ? '(blank)' : merged.totalAmount} ${merged.currency || ''}, Date: ${merged.receiptDate || '(blank)'}, Confidence: ${merged.confidence === '' ? '(blank)' : merged.confidence}`;
const aiResponseDetails = `Receipt parsed — ${aiSummary}`;
const missingDetails = `Routed to Pending Review. Missing fields: ${missingFields.join(', ')}`;

// Sheet row — matches Receipts sheet column order exactly:
// Employee Name | Submitted Date | Receipt Date | Merchant
// | Expense Category | Payment Method | Currency
// | Total Amount | VAT Included | VAT Amount | Status
const rowValues = [
  merged.discordUser,
  merged.submittedDate,
  merged.receiptDate,
  merged.merchant,
  merged.category,
  merged.paymentMethod,
  merged.currency,
  merged.totalAmount,
  merged.vatIncluded,
  merged.vatAmount,
  status
];

const discordMessage = hasMissingFields
  ? `🟡 <@${merged.discordUserId}> your receipt was detected, but it is missing required data.\n\n**Status:** Pending Review\n**Missing:** ${missingFields.join(', ')}\n\nPlease re-upload the receipt with the missing information.`
  : `✅ <@${merged.discordUserId}> your receipt was processed successfully.\n\n**Status:** Approved by Bot\n**Merchant:** ${merged.merchant}\n**Amount:** ${merged.totalAmount} ${merged.currency}\n**Category:** ${merged.category}`;

return [{
  json: {
    ...merged,
    apiUnavailable: false,
    receiptDetected: true,
    hasMissingFields,
    missingFields,
    status,
    details: aiResponseDetails,
    missingDetails,
    rowValues,
    aiRawText: parsed.aiRawText,
    logEvent: 'AIResponseReceived',
    logLabel: 'info',
    discordMessage
  }
}];
